/// @docimport 'connection.dart';
library;

import 'dart:collection';

import 'package:collection/collection.dart';

/// The result of running an SQL statement against a [DriftSession].
final class QueryResult {
  /// If known, the amount of rows affected by the statement.
  final int? affectedRows;

  /// For tables with an auto-incrementing primary key, the last rowid value
  /// generated by the statement.
  final int? lastInsertRowId;

  /// The result set containing column information and rows returned by running
  /// a query.
  ///
  /// This will only be set if the [StatementInfo] passed to
  /// [DriftSession.execute] has [StatementInfo.needsResultSet] enabled.
  final RawResultSet? resultSet;

  /// @nodoc
  const QueryResult({
    this.affectedRows,
    this.lastInsertRowId,
    required this.resultSet,
  });
}

/// A row in a [RawResultSet], a list of untyped values.
///
/// The Dart types of values in this row is unknown. A drift dialect
/// implementation is responsible for transforming them into the types
/// understood by drift.
typedef RawRow = List<Object?>;

/// A raw view of result sets returned by the connection implementation.
///
/// This provides [columnNames] and a list of [RawRow]s providing untyped access
/// to values without mapping them through drift's SQL type system.
abstract base class RawResultSet
    with ListMixin<RawRow>, NonGrowableListMixin<RawRow> {
  /// Names of all columns that appear in this result set.
  final List<String> columnNames;

  /// @nodoc
  RawResultSet({required this.columnNames});

  /// Creates a [RawResultSet] from column names and individual [rows].
  factory RawResultSet.fromRows({
    required List<String> columnNames,
    required List<RawRow> rows,
  }) = _ListResultSet;

  @override
  void operator []=(int index, RawRow value) {
    throw UnsupportedError("Can't change rows from a result set");
  }
}

final class _ListResultSet extends RawResultSet {
  final List<RawRow> _rows;

  _ListResultSet({required super.columnNames, required List<RawRow> rows})
    : _rows = rows;

  @override
  RawRow operator [](int index) {
    return _rows[index];
  }

  @override
  int get length => _rows.length;
}
